f=$(ls -t logs/sessions/*.jsonl | head -1); echo "=== $f ==="; python3 -c "
import json,sys
msgs=[json.loads(l) for l in open('$f') if l.strip()]
# print last assistant text blocks
for m in msgs:
    role=m.get('role') or (m.get('message',{}) or {}).get('role')
    content=m.get('content') or (m.get('message',{}) or {}).get('content')
    if role=='assistant' and content:
        if isinstance(content,list):
            for b in content:
                if isinstance(b,dict) and b.get('type')=='text' and b.get('text','').strip():
                    print(b['text'][:1500]); print('---')
" 2>&1 | tail -40
